	int totalRead = 0;

    if (hasHitEOF || entryOffset >= entrySize) {
        return -1;
    }

    if (currEntry == null) {
        throw new IllegalStateException("No current tar entry");
    }

    while (numToRead > 0) {
        int bytesRead = is.read(buf, offset, numToRead);
        if (bytesRead == -1) {
            hasHitEOF = true;
            break;
        } else if (bytesRead == 0) {
            // Handle case where no bytes are read, but not EOF
            break;
        }
        totalRead += bytesRead;
        offset += bytesRead;
        numToRead -= bytesRead;
        entryOffset += bytesRead;
        count(bytesRead);
    }

    return totalRead == 0 && hasHitEOF ? -1 : totalRead;
}

